module test (
  out_0,
  out_1,
  in_0,
  in_1);
output 	out_0;
output  out_1;
input 	in_0;
input 	in_1;

wire gnd;
wire vcc;

assign gnd = 1'b0;
assign vcc = 1'b1;

wire FIRST_combout;
wire SECOND_combout;

fourteennm_lcell_comb FIRST (
  .dataa(in_0),
  .datab(in_1),
  .datac(gnd),
  .datad(gnd),
  .datae(gnd),
  .dataf(gnd),
  .datag(gnd),
  .datah(gnd),
  .cin(gnd),
  .sharein(gnd),
  .combout(FIRST_combout),
  .sumout(),
  .cout(),
  .shareout());
defparam FIRST .extended_lut = "off";
defparam FIRST .lut_mask = 64'h1212121212121212;
defparam FIRST .shared_arith = "off";

fourteennm_lcell_comb SECOND (
  .dataa(in_0),
  .datab(in_1),
  .datac(gnd),
  .datad(gnd),
  .datae(gnd),
  .dataf(gnd),
  .datag(gnd),
  .datah(gnd),
  .cin(gnd),
  .sharein(gnd),
  .combout(SECOND_combout),
  .sumout(),
  .cout(),
  .shareout());
defparam SECOND .extended_lut = "off";
defparam SECOND .lut_mask = 64'h1234FFFFFFFF1234;
defparam SECOND .shared_arith = "off";

assign out_0 = FIRST_combout;
assign out_1 = SECOND_combout;

endmodule
